"use client";

import { UserButton, useUser } from "@clerk/nextjs";
import { usePathname, useRouter } from "next/navigation";
import Link from "next/link";
import { 
  BarChart, 
  Settings, 
  FileText, 
  Users, 
  Share2, 
  Image as ImageIcon, 
  ChevronRight,
  Bell,
  Search,
  Menu,
  X,
  ShieldCheck,
  Layout,
  Layers
} from "lucide-react";
import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";

const NAV_ITEMS = [
  { name: "Dashboard", href: "/admin", icon: BarChart },
  { name: "Sections", href: "/admin/sections", icon: Layers },
  { name: "Programs", href: "/admin/programs", icon: Layout },
  { name: "Courses", href: "/admin/courses", icon: FileText },
  { name: "Team", href: "/admin/team", icon: Users },
  { name: "Partners", href: "/admin/partners", icon: Share2 },
  { name: "Settings", href: "/admin/settings", icon: Settings },
];

export default function AdminLayout({ children }: { children: React.ReactNode }) {
  const { user, isLoaded } = useUser();
  const pathname = usePathname();
  const router = useRouter();
  const isLoginPage = pathname === "/admin/login";
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) return null;

  // If login page, don't show the full admin layout
  if (isLoginPage) {
    return <>{children}</>;
  }

  // Still show loading if user profile isn't fetched yet
  if (!isLoaded || !user) {
    return (
      <div className="h-screen w-full bg-slate-50 flex items-center justify-center">
        <div className="flex flex-col items-center gap-3">
          <div className="size-6 border-2 border-slate-200 border-t-primary rounded-full animate-spin"></div>
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Initialising Secure Session</span>
        </div>
      </div>
    );
  }

  const activeItem = NAV_ITEMS.find(item => item.href === pathname) || NAV_ITEMS[0];

  return (
    <div className="min-h-screen bg-slate-50 text-slate-600 font-sans selection:bg-primary/5 selection:text-primary overflow-hidden flex">
      {/* Sidebar */}
      <aside 
        className={`bg-white border-r border-slate-200 shadow-sm transition-all duration-300 ease-in-out flex flex-col z-50 ${
          isSidebarOpen ? "w-60" : "w-16"
        }`}
      >
        <div className="h-14 flex items-center px-4 border-b border-slate-100 mb-2">
           <div className="size-7 bg-primary rounded-lg flex items-center justify-center shadow-sm">
              <ShieldCheck className="text-white size-4" />
           </div>
           {isSidebarOpen && (
             <span className="ml-3 font-bold text-sm tracking-tight text-slate-900 uppercase">Orphosys <span className="text-primary font-black">Admin</span></span>
           )}
        </div>

        <nav className="flex-1 px-2 py-2 space-y-1 overflow-y-auto scrollbar-hide">
          {NAV_ITEMS.map((item) => {
            const isActive = pathname === item.href;
            return (
              <Link
                key={item.href}
                href={item.href}
                className={`flex items-center gap-3 px-3 py-2 rounded-lg transition-all text-xs font-bold ${
                  isActive 
                    ? "bg-primary/5 text-primary" 
                    : "text-slate-400 hover:bg-slate-50 hover:text-slate-600"
                }`}
              >
                <item.icon className={`size-4 ${isActive ? "text-primary" : "text-slate-400"}`} />
                {isSidebarOpen && <span>{item.name}</span>}
              </Link>
            );
          })}
        </nav>

        <div className="p-3 border-t border-slate-100">
           <div className={`flex items-center gap-3 ${isSidebarOpen ? "" : "justify-center"}`}>
              <UserButton appearance={{ elements: { userButtonAvatarBox: "size-7" } }} />
              {isSidebarOpen && (
                <div className="min-w-0">
                  <p className="text-[11px] font-bold text-slate-900 truncate leading-none">{user.firstName}</p>
                  <p className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter mt-1">Admin Access</p>
                </div>
              )}
           </div>
        </div>
      </aside>

      {/* Main Area */}
      <div className="flex-1 flex flex-col h-screen min-w-0">
        <header className="h-14 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 flex items-center justify-between sticky top-0 z-40">
           <div className="flex items-center gap-4">
              <button 
                onClick={() => setIsSidebarOpen(!isSidebarOpen)} 
                className="p-1.5 hover:bg-slate-100 rounded-md text-slate-400 transition-colors"
              >
                {isSidebarOpen ? <X className="size-4" /> : <Menu className="size-4" />}
              </button>
              <div className="h-4 w-px bg-slate-200 mx-1"></div>
              <div className="flex items-center gap-2 text-xs font-bold text-slate-400 uppercase tracking-widest translate-y-[0.5px]">
                 <span>System</span>
                 <ChevronRight className="size-3" />
                 <span className="text-slate-900">{activeItem.name}</span>
              </div>
           </div>

           <div className="flex items-center gap-4">
              <div className="hidden sm:flex items-center bg-slate-100 px-3 py-1.5 rounded-lg border border-slate-200 w-64 group">
                 <Search className="size-3.5 text-slate-400 mr-2" />
                 <input type="text" placeholder="Search parameters..." className="bg-transparent border-none text-[11px] font-medium outline-none w-full placeholder:text-slate-400" />
              </div>
              <button className="p-2 text-slate-400 hover:text-slate-600 transition-colors relative">
                 <Bell className="size-4" />
                 <span className="absolute top-2 right-2 size-1.5 bg-red-500 rounded-full border-2 border-white"></span>
              </button>
           </div>
        </header>

        <main className="flex-1 overflow-y-auto bg-slate-50/50 p-6">
          <div className="max-w-6xl mx-auto">
             <AnimatePresence mode="wait">
               <motion.div
                 key={pathname}
                 initial={{ opacity: 0, y: 5 }}
                 animate={{ opacity: 1, y: 0 }}
                 transition={{ duration: 0.2 }}
               >
                 {children}
               </motion.div>
             </AnimatePresence>
          </div>
        </main>
      </div>
    </div>
  );
}
